import logo from "./logo.png";
import styles from "./Header.module.css";

const Header = () => {
  return (
    <header className={styles.header}>
      <img src={logo} />
      <div className={styles.logoText}>Welcome to "FacebookKiller"</div>
    </header>
  );
};

export default Header;
